const item = $input.first();
const payload = item.json ?? {};
const csvText = String(payload.body ?? payload.data ?? payload.stdout ?? '').trim();
const detail = JSON.stringify(Object.keys(payload));
if (!csvText) {
  throw new Error(`ClubSpark exporter did not return CSV output. Payload keys: ${detail}`);
}
if (/^<!DOCTYPE html/i.test(csvText) || /^<html/i.test(csvText) || /<title>.*Sign in/i.test(csvText)) {
  throw new Error('ClubSpark exporter returned HTML instead of CSV. The browser login did not complete successfully.');
}
function parseCsv(text) {
  const rows = [];
  let row = [], field = '', inQuotes = false;
  for (let i = 0; i < text.length; i++) {
    const ch = text[i], next = text[i + 1];
    if (inQuotes) {
      if (ch === '"' && next === '"') { field += '"'; i++; }
      else if (ch === '"') { inQuotes = false; }
      else { field += ch; }
    } else {
      if (ch === '"') { inQuotes = true; }
      else if (ch === ',') { row.push(field); field = ''; }
      else if (ch === '\r' && next === '\n') { row.push(field); field = ''; rows.push(row); row = []; i++; }
      else if (ch === '\n' || ch === '\r') { row.push(field); field = ''; rows.push(row); row = []; }
      else { field += ch; }
    }
  }
  if (field || row.length) { row.push(field); rows.push(row); }
  return rows;
}
const allRows = parseCsv(csvText);
if (allRows.length < 2) throw new Error(`CSV has fewer than 2 rows (got ${allRows.length}).`);
const headers = allRows[0].map((h) => h.trim());
if (!headers.includes('First name') || !headers.includes('Last name')) {
  throw new Error(`ClubSpark export did not return the expected contacts CSV headers. Got: ${headers.slice(0, 8).join(', ')}`);
}
const dataRows = allRows.slice(1).filter((r) => r.some((c) => c.trim() !== ''));
if (!dataRows.length) {
  return [{ json: { rowCount: 0, message: 'No data rows in CSV export.' } }];
}
return dataRows.map((row) => ({ json: Object.fromEntries(headers.map((h, i) => [h, (row[i] ?? '').trim()])) }));

const sqlLiteral = (value) => {
  if (value === null || value === undefined || value === '') return 'NULL';
  return `'${String(value).replace(/'/g, "''")}'`;
};
const rows = $input.all().map((item) => item.json ?? {});
if (!rows.length) {
  throw new Error('No parsed contact rows were available to build the import SQL.');
}
const values = rows.map((row) => {
  const firstName = sqlLiteral(row['First name'] ?? row['first name'] ?? '');
  const lastName  = sqlLiteral(row['Last name']  ?? row['last name']  ?? '');
  const address1  = sqlLiteral(row['Address 1']  ?? row['address 1'] ?? '');
  const address2  = sqlLiteral(row['Address 2']  ?? row['address 2'] ?? '');
  const address3  = sqlLiteral(row['Address 3']  ?? row['address 3'] ?? '');
  const town      = sqlLiteral(row['town']       ?? row['Town']      ?? '');
  const postcode  = sqlLiteral(row['postcode']   ?? row['Postcode']  ?? '');
  return `(${firstName}, ${lastName}, ${address1}, ${address2}, ${address3}, ${town}, ${postcode})`;
}).join(',\n  ');
const sql = `BEGIN;\nSELECT * FROM public.prepare_raw_contacts_import();\nINSERT INTO raw_contacts ("First name", "Last name", "Address 1", "Address 2", "Address 3", town, postcode)\nVALUES\n  ${values};\nCOMMIT;`;
return [{ json: { sql, rowCount: rows.length } }];
